package com.zephyr.watch.api;

import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.ResponseBody;

@Controller
public class DashboardPageController {

    @GetMapping(value = "/dashboard", produces = "text/html;charset=UTF-8")
    @ResponseBody
    public String dashboard() {
        return "<!doctype html>\n<html lang=\"zh-CN\">\n<head>\n  <meta charset=\"UTF-8\">\n  <title>Zephyr Watch \u770b\u677f</title>\n  <style>\n    body{margin:0;font-family:Arial,sans-serif;background:#f5f7fb;color:#172033} header{padding:22px 28px;background:#172033;color:white} main{padding:22px} .cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:14px;margin-bottom:18px}.card,.panel{background:white;border-radius:12px;padding:16px;box-shadow:0 4px 14px rgba(23,32,51,.08)}.card b{display:block;font-size:26px;margin-top:8px}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:14px}.panel h3{margin:0 0 12px}.bar{display:flex;justify-content:space-between;border-bottom:1px solid #edf0f5;padding:7px 0}table{width:100%;border-collapse:collapse;font-size:13px}th,td{padding:8px;border-bottom:1px solid #edf0f5;text-align:left;vertical-align:top}th{background:#f0f3f8}.error{padding:12px;border-radius:10px;background:#fff2f0;color:#a8071a;margin:14px 0;display:none}.wide{grid-column:1/-1;overflow:auto}\n  </style>\n</head>\n<body>\n<header><h2>Zephyr Watch \u4e1a\u52a1\u770b\u677f</h2><div>\u98ce\u9669\u9884\u6d4b\u3001\u544a\u8b66\u4e8b\u4ef6\u4e0e\u7ef4\u4fee\u63a8\u8350\u4e1a\u52a1\u76d1\u63a7</div></header>\n<main>\n  <div id=\"error\" class=\"error\"></div>\n  <section class=\"cards\" id=\"overview\"></section>\n  <section class=\"grid\">\n    <div class=\"panel\"><h3>\u98ce\u9669\u7b49\u7ea7\u5206\u5e03</h3><div id=\"riskLevels\"></div></div>\n    <div class=\"panel\"><h3>\u544a\u8b66\u7c7b\u578b\u5206\u5e03</h3><div id=\"alertTypes\"></div></div>\n    <div class=\"panel\"><h3>\u8bbe\u5907\u98ce\u9669 TopN</h3><div id=\"topMachines\"></div></div>\n    <div class=\"panel wide\"><h3>\u6700\u65b0\u9884\u6d4b\u8bb0\u5f55</h3><div id=\"latestPredictions\"></div></div>\n    <div class=\"panel wide\"><h3>\u6700\u65b0\u544a\u8b66\u8bb0\u5f55</h3><div id=\"latestAlerts\"></div></div>\n    <div class=\"panel wide\"><h3>\u6700\u65b0\u7ef4\u4fee\u63a8\u8350</h3><div id=\"latestRecommendations\"></div></div>\n  </section>\n</main>\n<script>\nconst api = p => fetch(p).then(r => { if(!r.ok) throw new Error(p + ' ' + r.status); return r.json(); }).then(j => j.data || j);\nconst showError = e => { const box=document.getElementById('error'); box.style.display='block'; box.textContent='\u52a0\u8f7d\u5931\u8d25\uff1a' + e.message; };\nconst fmt = v => v === null || v === undefined ? '' : v;\nfunction cards(o){ document.getElementById('overview').innerHTML = [\n  ['\u9884\u6d4b\u603b\u6570', o.predictionCount], ['\u9ad8\u98ce\u9669\u8bbe\u5907\u6570', o.highRiskMachineCount], ['\u544a\u8b66\u603b\u6570', o.alertCount], ['\u63a8\u8350\u603b\u6570', o.recommendationCount], ['\u53cd\u9988\u603b\u6570', o.feedbackCount]\n].map(x => `<div class=\"card\"><span>${x[0]}</span><b>${fmt(x[1])}</b></div>`).join(''); }\nfunction list(id, rows, nameKey, valueKey){ document.getElementById(id).innerHTML = (rows||[]).map(r => `<div class=\"bar\"><span>${fmt(r[nameKey])}</span><b>${fmt(r[valueKey])}</b></div>`).join('') || '\u6682\u65e0\u6570\u636e'; }\nfunction table(id, rows, cols){ if(!rows || rows.length===0){ document.getElementById(id).innerHTML='\u6682\u65e0\u6570\u636e'; return; } document.getElementById(id).innerHTML = `<table><thead><tr>${cols.map(c=>`<th>${c[0]}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${cols.map(c=>`<td>${fmt(r[c[1]])}</td>`).join('')}</tr>`).join('')}</tbody></table>`; }\nPromise.all([\n api('/api/dashboard/overview'), api('/api/dashboard/risk-level-distribution'), api('/api/dashboard/alert-type-distribution'), api('/api/dashboard/top-risk-machines?limit=10'), api('/api/dashboard/latest-predictions?limit=10'), api('/api/dashboard/latest-alerts?limit=10'), api('/api/dashboard/latest-recommendations?limit=10')\n]).then(([o,rl,at,tm,lp,la,lr]) => {\n cards(o); list('riskLevels', rl, 'riskLevel', 'total'); list('alertTypes', at, 'alertType', 'total'); list('topMachines', tm, 'machineId', 'maxRiskProbability');\n table('latestPredictions', lp, [['\u9884\u6d4bID','predictionId'],['\u8bbe\u5907ID','machineId'],['\u5269\u4f59\u5bff\u547d','rul'],['\u98ce\u9669\u6982\u7387','riskProbability'],['\u98ce\u9669\u7b49\u7ea7','riskLevel'],['\u6a21\u578b\u7248\u672c','modelVersion']]);\n table('latestAlerts', la, [['\u544a\u8b66ID','alertId'],['\u8bbe\u5907ID','machineId'],['\u544a\u8b66\u7c7b\u578b','alertType'],['\u98ce\u9669\u7b49\u7ea7','riskLevel'],['\u98ce\u9669\u6982\u7387','riskProbability'],['\u72b6\u6001','status'],['\u544a\u8b66\u6d88\u606f','message']]);\n table('latestRecommendations', lr, [['\u63a8\u8350ID','recommendationId'],['\u544a\u8b66ID','alertId'],['\u8bbe\u5907ID','machineId'],['\u5de5\u5355\u4f18\u5148\u7ea7','workOrderPriority'],['\u63a8\u8350\u52a8\u4f5c','action'],['\u63a8\u8350\u5907\u4ef6','spareParts'],['\u76f8\u4f3c\u6848\u4f8b','similarCaseId'],['\u63a8\u8350\u5206\u6570','score']]);\n}).catch(showError);\n</script>\n</body>\n</html>";
    }
}
